import{_ as t,o as a,c as o,ag as n}from"./chunks/framework.OsDJF_Ea.js";const u=JSON.parse('{"title":"Plan Analysis & DAG","description":"","frontmatter":{},"headers":[],"relativePath":"plan-analysis.md","filePath":"plan-analysis.md"}'),s={name:"plan-analysis.md"};function r(i,e,l,d,c,p){return a(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="plan-analysis-dag" tabindex="-1">Plan Analysis &amp; DAG <a class="header-anchor" href="#plan-analysis-dag" aria-label="Permalink to &quot;Plan Analysis &amp; DAG&quot;">​</a></h1><p>After a dry run, CatalystOps surfaces the physical Catalyst plan in an interactive sidebar tree and a full-page DAG webview.</p><h2 id="explain-plan-tree" tabindex="-1">Explain Plan Tree <a class="header-anchor" href="#explain-plan-tree" aria-label="Permalink to &quot;Explain Plan Tree&quot;">​</a></h2><p>The <strong>Explain Plan</strong> sidebar panel shows the physical plan as a collapsible tree. Each node displays:</p><ul><li>Operator name (e.g. <code>BroadcastHashJoin</code>, <code>FileScan</code>, <code>Exchange</code>)</li><li>Cost score — a normalized 0–100 value based on the operator&#39;s performance impact</li><li>Issue badge when a plan-level problem is detected on that node</li><li>Source line mapping (when available) to navigate back to the originating DataFrame</li></ul><h2 id="dag-webview" tabindex="-1">DAG Webview <a class="header-anchor" href="#dag-webview" aria-label="Permalink to &quot;DAG Webview&quot;">​</a></h2><p>Click the <strong>Show Plan DAG</strong> button or run <strong>CatalystOps: Show Plan DAG</strong> from the Command Palette to open an interactive tree view:</p><ul><li><code>└─</code> / <code>├─</code> connectors showing operator relationships</li><li>Query groups collapsed into accordions with execution counts</li><li>Filter conditions rendered in plain English (<code>col not null</code>, <code>a AND b</code>)</li><li>Issue badges on affected nodes</li><li><strong>View Source</strong> button to jump to the notebook/file that generated the plan</li><li>Collapsible <strong>Raw Plans</strong> section for debugging</li></ul><h2 id="quick-fixes-on-plan-nodes" tabindex="-1">Quick Fixes on Plan Nodes <a class="header-anchor" href="#quick-fixes-on-plan-nodes" aria-label="Permalink to &quot;Quick Fixes on Plan Nodes&quot;">​</a></h2><p>Right-click any plan node (or use the inline action buttons) for context-aware quick fixes:</p><table tabindex="0"><thead><tr><th>Fix</th><th>When Available</th><th>What It Does</th></tr></thead><tbody><tr><td><strong>Add Broadcast Hint</strong></td><td>Sort-merge join where one side is small</td><td>Inserts <code>broadcast()</code> on the smaller side</td></tr><tr><td><strong>Add Repartition</strong></td><td>Unnecessary exchange / skewed shuffle</td><td>Inserts <code>.repartition(200)</code> before the join or groupBy</td></tr><tr><td><strong>Add Persist</strong></td><td>Repeated scan of the same DataFrame</td><td>Inserts <code>df = df.persist()</code> after the assignment</td></tr><tr><td><strong>Enable AQE</strong></td><td>Sort-merge join that AQE could convert</td><td>Inserts <code>spark.conf.set(&quot;spark.sql.adaptive.enabled&quot;, &quot;true&quot;)</code> at the top</td></tr><tr><td><strong>Add Join Condition</strong></td><td>Cartesian product</td><td>Prompts for a key name and replaces <code>.crossJoin()</code> with <code>.join()</code></td></tr></tbody></table>',11)])])}const g=t(s,[["render",r]]);export{u as __pageData,g as default};
